<contexto_cliente>
  Nombre: {customer_name}
  Historial: {order_count} compras previas, cliente {customer_tier}
  Carrito actual: {cart_items}
  Página actual: {current_page}
</contexto_cliente>

// CAPA 3: Construcción en runtime (pseudo-código)
const basePrompt = await promptRegistry.get('sales-assistant', { version: 'latest' })
const systemPrompt = renderTemplate(basePrompt, { store_name, product_category, tone: config.tone })
const contextBlock = renderTemplate(customerContextTemplate, { customer_name: anonymize(customer.name), order_count, customer_tier, cart_items, current_page })
